import{_ as e,o as a,c as i,a4 as r}from"./chunks/framework.EG5hAXdg.js";const y=JSON.parse('{"title":"Price examples","description":"This page list examples of yearly cost for selected use cases in HUNT Cloud.","frontmatter":{"title":"Price examples","category":"HUNT Cloud","permalink":"/administer-science/prices/examples","outline":"2-3","description":"This page list examples of yearly cost for selected use cases in HUNT Cloud."},"headers":[],"relativePath":"administer-science/prices/examples.md","filePath":"administer-science/prices/examples.md"}'),d={name:"administer-science/prices/examples.md"};function s(l,t,n,o,h,g){return a(),i("div",null,[...t[0]||(t[0]=[r('<h1 id="price-examples" tabindex="-1">Price examples <a class="header-anchor" href="#price-examples" aria-label="Permalink to &quot;Price examples&quot;">​</a></h1><p><strong>We know, the complexity of flexible cloud prices is demanding. Bare with us, because the flexibility opens opportunities. Here are a few examples to give you a pricing direction.</strong></p><nav class="table-of-contents"><ul><li><a href="#epidemiology">Epidemiology</a></li><li><a href="#genomics">Genomics</a></li><li><a href="#machine-learning">Machine learning</a></li><li><a href="#data-archives">Data archives</a></li></ul></nav><p>For the record, all prices in the examples are listed as VAT exclusive in NOK from the <a href="/administer-science/prices/pricelist">price list</a>. The prices are provided for guidance and may contain both errors and outdated information.</p><div class="tip custom-block"><p class="custom-block-title">Estimate your specific cost</p><p>Head over to our <a href="/administer-science/prices/estimator">pricing estimator</a> to calculate the cost for your specific scientific environment, and do not hesitate to <a href="/contact">contact us</a> for assistance.</p></div><h2 id="epidemiology" tabindex="-1">Epidemiology <a class="header-anchor" href="#epidemiology" aria-label="Permalink to &quot;Epidemiology&quot;">​</a></h2><p>This is a typical lab tailored for data analysis of structured data, such as health registries and survey data.</p><table tabindex="0"><thead><tr><th>Service</th><th>Description</th><th>Type</th><th style="text-align:right;">Cost/unit</th><th style="text-align:right;">Units</th><th style="text-align:right;">Total cost</th></tr></thead><tbody><tr><td>Lab</td><td>subscription</td><td>1 year</td><td style="text-align:right;">9354</td><td style="text-align:right;">1</td><td style="text-align:right;">9354</td></tr><tr><td>Compute</td><td><a href="/administer-science/services/machine-types#c-series">default.c1</a></td><td>1 year</td><td style="text-align:right;">5360</td><td style="text-align:right;">1</td><td style="text-align:right;">5360</td></tr><tr><td>Store</td><td>1 TB regular storage</td><td>1 year</td><td style="text-align:right;">2844</td><td style="text-align:right;">1</td><td style="text-align:right;">2844</td></tr><tr><td><strong>PER YEAR</strong></td><td></td><td></td><td style="text-align:right;"></td><td style="text-align:right;"></td><td style="text-align:right;"><strong>17558</strong></td></tr></tbody></table><p>The above example establishes your own lab in HUNT Cloud with access to commonly used tools in HUNT Workbench. Your lab holds sufficient resources for analysis for a small team: 2 vCPUs and 8 GB of memory, and the minimum allocation of 1 TB storage. Resources can easily be upgraded as your experiments grow.</p><h2 id="genomics" tabindex="-1">Genomics <a class="header-anchor" href="#genomics" aria-label="Permalink to &quot;Genomics&quot;">​</a></h2><p>This is an example of a lab for larger genomics analysis, for example when you need a lab to store and analyze genomics data from several sources using a varied set of tools.</p><table tabindex="0"><thead><tr><th>Service</th><th>Description</th><th>Type</th><th style="text-align:right;">Cost/unit</th><th style="text-align:right;">Units</th><th style="text-align:right;">Total cost</th></tr></thead><tbody><tr><td>Lab</td><td>subscription</td><td>1 year</td><td style="text-align:right;">9354</td><td style="text-align:right;">1</td><td style="text-align:right;">9354</td></tr><tr><td>Compute</td><td><a href="/administer-science/services/machine-types#b-series">default.b5</a></td><td>1 year</td><td style="text-align:right;">41462</td><td style="text-align:right;">1</td><td style="text-align:right;">41462</td></tr><tr><td>Store</td><td>10 TB regular storage</td><td>1 year</td><td style="text-align:right;">2844</td><td style="text-align:right;">10</td><td style="text-align:right;">28440</td></tr><tr><td><strong>PER YEAR</strong></td><td></td><td></td><td style="text-align:right;"></td><td style="text-align:right;"></td><td style="text-align:right;"><strong>79256</strong></td></tr></tbody></table><p>The above example establishes your own lab in HUNT Cloud, a powerful machine fit for larger analysis (32 vCPU and 64 GB memory), and storage capacity to run both experiments and archive larger data sets (10 TB).</p><p>The cost can be reduced by running a smaller machine size for day-to-day activities and then upgrading to larger on-demand machines in analysis intensive periods.</p><h2 id="machine-learning" tabindex="-1">Machine learning <a class="header-anchor" href="#machine-learning" aria-label="Permalink to &quot;Machine learning&quot;">​</a></h2><p>This is an example of a machine learning lab with mixed activities that require data storage, computational power and graphical accelerators.</p><table tabindex="0"><thead><tr><th>Service</th><th>Description</th><th>Type</th><th style="text-align:right;">Cost/unit</th><th style="text-align:right;">Units</th><th style="text-align:right;">Total cost</th></tr></thead><tbody><tr><td>Lab</td><td>subscription</td><td>1 year</td><td style="text-align:right;">9354</td><td style="text-align:right;">1</td><td style="text-align:right;">9354</td></tr><tr><td>Compute</td><td><a href="/administer-science/services/machine-types#c-series">default.c1</a></td><td>1 year</td><td style="text-align:right;">5360</td><td style="text-align:right;">1</td><td style="text-align:right;">5360</td></tr><tr><td>Compute</td><td><a href="/administer-science/services/machine-types#d-series">default.d3</a></td><td>1 year</td><td style="text-align:right;">28748</td><td style="text-align:right;">1</td><td style="text-align:right;">28748</td></tr><tr><td>Compute</td><td><a href="/administer-science/services/machine-types#gpu-accelerator-types">nvidia.l40s</a></td><td>1 year</td><td style="text-align:right;">23425</td><td style="text-align:right;">1</td><td style="text-align:right;">23425</td></tr><tr><td>Store</td><td>10 TB regular storage</td><td>1 year</td><td style="text-align:right;">2844</td><td style="text-align:right;">10</td><td style="text-align:right;">28440</td></tr><tr><td>Store</td><td>5 TB speed-optimized storage</td><td>1 year</td><td style="text-align:right;">5524</td><td style="text-align:right;">10</td><td style="text-align:right;">27625</td></tr><tr><td><strong>PER YEAR</strong></td><td></td><td></td><td style="text-align:right;"></td><td style="text-align:right;"></td><td style="text-align:right;"><strong>122478</strong></td></tr></tbody></table><p>The above example establishes your own lab in HUNT Cloud. The compute resources are split in two machines: a smaller home machine (default.c1 with 2 vCPU and 8 GB memory) for data handling and day-to-day activities, and a larger machine (default.d3 with 8 vCPU and 64 GB memory) that has attached one enterprise GPU card (NVIDIA L40S with 48 GB memory). The lab holds 10 TB regular storage for archive and 5 TB of speed-optimized storage (NVMe) for the GPU machine. The cost may be reduced by using on-demand compute resources when GPU.</p><h2 id="data-archives" tabindex="-1">Data archives <a class="header-anchor" href="#data-archives" aria-label="Permalink to &quot;Data archives&quot;">​</a></h2><p>This is an example of a large data archive, such as a biobank or image archive that manages data for reuse. The configuration exemplifies a data archive holding 200 TB of data with 90 days of intensive data quality control per year.</p><table tabindex="0"><thead><tr><th>Service</th><th>Description</th><th>Type</th><th style="text-align:right;">Cost/unit</th><th style="text-align:right;">Units</th><th style="text-align:right;">Total cost</th></tr></thead><tbody><tr><td>Lab</td><td>subscription</td><td>1 year</td><td style="text-align:right;">9354</td><td style="text-align:right;">1</td><td style="text-align:right;">9354</td></tr><tr><td>Compute</td><td><a href="/administer-science/services/machine-types#c-series">default.c1</a></td><td>1 year</td><td style="text-align:right;">5360</td><td style="text-align:right;">1</td><td style="text-align:right;">5360</td></tr><tr><td>Compute</td><td><a href="/administer-science/services/machine-types#b-series">default.b4</a></td><td>1 day</td><td style="text-align:right;">52.25</td><td style="text-align:right;">90</td><td style="text-align:right;">4702</td></tr><tr><td>Store</td><td>First 10 TB regular storage</td><td>1 year</td><td style="text-align:right;">2844</td><td style="text-align:right;">10</td><td style="text-align:right;">28440</td></tr><tr><td>Store</td><td>Next 90 TB regular storage</td><td>1 year</td><td style="text-align:right;">2188</td><td style="text-align:right;">90</td><td style="text-align:right;">196920</td></tr><tr><td>Store</td><td>Next 100 TB regular storage</td><td>1 year</td><td style="text-align:right;">1641</td><td style="text-align:right;">100</td><td style="text-align:right;">164100</td></tr><tr><td><strong>PER YEAR</strong></td><td></td><td></td><td style="text-align:right;"></td><td style="text-align:right;"></td><td style="text-align:right;"><strong>408876</strong></td></tr></tbody></table><p>The above examples gives you a lab with a home machine intended for basic data activities. On-demand compute resources is allocated for 90 days for intensive quality control activities.</p><p>Storage above 10 TB obtains a volume discounts ending at a mean TB price of NOK 1947. The total cost may be significantly reduced by initiating a layered preservation strategies that utilizes tapes for duplicate copies.</p>',23)])])}const p=e(d,[["render",s]]);export{y as __pageData,p as default};
